export const messages: Record<Locale, Record<MessageKey, string>> = { "zh-Hans": zh, ja, en };

const englishSingularMessages: Partial<Record<MessageKey, string>> = {
  "discover.resultCount": "{count} event · Japan time",
  "event.completedEvents": "{count} event completed",
};

export function isLocale(value: string | null | undefined): value is Locale {
  return locales.includes(value as Locale);
}

export function formatMessage(locale: Locale, key: MessageKey, values?: Record<string, string | number>): string {
  let value = locale === "en" && values?.count === 1
    ? englishSingularMessages[key] ?? messages[locale][key]
    : messages[locale][key] ?? messages["zh-Hans"][key];
  for (const [name, replacement] of Object.entries(values ?? {})) value = value.replaceAll(`{${name}}`, String(replacement));
  return value;
}

export type { MessageKey };
